   436→  font-weight: 600;
   437→  text-transform: uppercase;
   438→  letter-spacing: 0.05em;
   439→  color: var(--accent);
   440→  margin-bottom: 0.4rem;
   441→}
   442→
   443→/* ── Metadata table ── */
   444→.meta-table { font-size: 0.85rem; margin-bottom: 1.25rem; }
   445→.meta-table td:first-child { color: var(--text-muted); width: 140px; font-weight: 500; }
   446→
   447→/* ── Backlinks ── */
   448→.backlinks {
   449→  background: var(--bg-secondary);
   450→  border: 1px solid var(--border);
   451→  border-radius: 6px;
   452→  padding: 0.75rem 1rem;
   453→  margin-bottom: 1.25rem;
   454→  font-size: 0.85rem;
   455→}
   456→
   457→.backlinks-title { font-weight: 600; color: var(--text-muted); margin-bottom: 0.4rem; font-size: 0.8rem; text-transform: uppercase; }
   458→.backlinks ul { padding-left: 1rem; }
   459→
   460→/* ── Search ── */
   461→.search-box {
   462→  width: 100%;
   463→  background: var(--bg-card);
   464→  border: 1px solid var(--border);
   465→  border-radius: 8px;
   466→  padding: 0.75rem 1rem;
   467→  color: var(--text);
   468→  font-size: 1rem;
   469→  font-family: inherit;
   470→  margin-bottom: 1rem;
   471→  outline: none;
   472→  transition: border-color 0.15s;
   473→}
   474→
   475→.search-box:focus { border-color: var(--accent); }
   476→
   477→.search-results { display: flex; flex-direction: column; gap: 0.75rem; }
   478→
   479→.search-result {
   480→  background: var(--bg-card);
   481→  border: 1px solid var(--border);
   482→  border-radius: 8px;
   483→  padding: 1rem;
   484→  transition: border-color 0.15s;
   485→}
   486→
   487→.search-result:hover { border-color: var(--accent); }
   488→.search-result-title { font-weight: 600; margin-bottom: 0.25rem; }
   489→.search-result-meta { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 0.5rem; }
   490→.search-result-snippet { font-size: 0.85rem; color: var(--text-muted); }
   491→.search-result mark { background: var(--mark-bg); color: var(--warning); border-radius: 2px; padding: 0 0.1em; }
   492→#search-count { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 0.75rem; }
   493→
   494→/* ── Heatmap legend ── */
   495→.heatmap-legend {
   496→  display: flex;
   497→  align-items: center;
   498→  gap: 0.4rem;
   499→  font-size: 0.75rem;
   500→  color: var(--text-muted);
   501→  margin-top: 0.5rem;
   502→  justify-content: flex-end;
   503→}
   504→
   505→/* ── Popover ── */
   506→.popover {
   507→  position: fixed;
   508→  z-index: 500;
   509→  background: var(--bg-card);
   510→  border: 1px solid var(--border);
   511→  border-radius: 8px;
   512→  padding: 0.75rem 1rem;
   513→  max-width: 320px;
   514→  font-size: 0.85rem;
   515→  box-shadow: 0 8px 24px rgba(0,0,0,0.4);
   516→  pointer-events: none;
   517→}
   518→
   519→.popover-meta { color: var(--text-muted); font-size: 0.78rem; margin-bottom: 0.4rem; }
   520→.popover-summary { color: var(--text); line-height: 1.5; }
   521→
   522→/* ── Graph canvas ── */
   523→#graph-canvas {
   524→  display: block;
   525→  width: 100%;
   526→  height: 600px;
   527→  border: 1px solid var(--border);
   528→  border-radius: 8px;
   529→  background: var(--bg-secondary);
   530→  cursor: grab;
   531→}
   532→
   533→#graph-canvas:active { cursor: grabbing; }
   534→
   535→.graph-legend {
   536→  display: flex;
   537→  gap: 1.25rem;
   538→  flex-wrap: wrap;
   539→  margin-top: 0.75rem;
   540→  font-size: 0.8rem;
   541→  color: var(--text-muted);
   542→}
   543→
   544→.graph-legend-item {
   545→  display: flex;
   546→  align-items: center;
   547→  gap: 0.4rem;
   548→}
   549→
   550→.graph-legend-dot {
   551→  width: 10px;
   552→  height: 10px;
   553→  border-radius: 50%;
   554→  flex-shrink: 0;
   555→}
   556→
   557→/* ── Project cards ── */
   558→.project-grid {
   559→  display: grid;
   560→  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
   561→  gap: 1rem;
   562→  margin-bottom: 1.5rem;
   563→}
   564→
   565→.project-card {
   566→  background: var(--bg-card);
   567→  border: 1px solid var(--border);
   568→  border-radius: 8px;
   569→  padding: 1.25rem;
   570→  transition: border-color 0.15s;
   571→}
   572→
   573→.project-card:hover { border-color: var(--accent); }
   574→.project-card-name { font-weight: 700; font-size: 1.05rem; margin-bottom: 0.5rem; }
   575→.project-card-meta { font-size: 0.82rem; color: var(--text-muted); }
   576→.project-card-clients { margin-top: 0.6rem; display: flex; gap: 0.35rem; flex-wrap: wrap; }
   577→
   578→/* ── Responsive: tablet icon mode (768–1024px) ── */
   579→@media (max-width: 1024px) and (min-width: 769px) {
   580→  :root { --sidebar-width: 52px; }
   581→  .nav-link .nav-label { display: none; }
   582→  .nav-link { justify-content: center; padding: 0.55rem; gap: 0; }
   583→  .nav-section-label { display: none; }
   584→  .sidebar-brand { display: none; }
   585→  .sidebar-footer .theme-label { display: none; }
   586→  .sidebar-footer .theme-toggle-btn { padding: 0.35rem 0.5rem; }
   587→}
   588→
   589→/* ── Responsive: mobile (<768px) ── */
   590→@media (max-width: 768px) {
   591→  .topbar { display: flex; }
   592→  .sidebar {
   593→    transform: translateX(-100%);
   594→    top: 48px;
   595→  }
   596→  .sidebar.open { transform: translateX(0); }
   597→  .sidebar-overlay.open { display: block; }
   598→  .main-content { margin-left: 0; }
   599→  .container { padding: 1rem 0.75rem; }
   600→  .stats-grid { grid-template-columns: repeat(2, 1fr); }
   601→  .project-grid { grid-template-columns: 1fr; }
   602→}
   603→
   604→/* ── Sidebar collapse ── */
   605→body.sidebar-collapsed .sidebar { width: 52px; }
   606→body.sidebar-collapsed .nav-label { display: none; }
   607→body.sidebar-collapsed .nav-link { justify-content: center; padding: 0.55rem; gap: 0; }
   608→body.sidebar-collapsed .nav-section-label { display: none; }
   609→body.sidebar-collapsed .sidebar-brand { display: none; }
   610→body.sidebar-collapsed .theme-label { display: none; }
   611→body.sidebar-collapsed .main-content { margin-left: 52px; }
   612→.sidebar-collapse-btn {
   613→  background: none;
   614→  border: 1px solid var(--border);
   615→  color: var(--text-muted);
   616→  border-radius: 6px;
   617→  padding: 0.25rem 0.5rem;
   618→  cursor: pointer;
   619→  font-size: 0.75rem;
   620→  line-height: 1;
   621→}
   622→.sidebar-collapse-btn:hover { color: var(--text); background: var(--bg-card); }
   623→
   624→/* ── Breadcrumb ── */
   625→.breadcrumb {
   626→  display: flex;
   627→  align-items: center;
   628→  flex-wrap: wrap;
   629→  gap: 0.25rem;
   630→  font-size: 0.82rem;
   631→  color: var(--text-muted);
   632→  margin-bottom: 1rem;
   633→}
   634→.breadcrumb-item { color: var(--text-muted); }
   635→a.breadcrumb-item { color: var(--accent); text-decoration: none; }
   636→a.breadcrumb-item:hover { text-decoration: underline; }
   637→.breadcrumb-sep { color: var(--border); user-select: none; }
   638→
   639→/* ── TOC ── */
   640→.toc {
   641→  background: var(--bg-secondary);
   642→  border: 1px solid var(--border);
   643→  border-left: 3px solid var(--accent);
   644→  border-radius: 6px;
   645→  padding: 0.75rem 1rem;
   646→  margin-bottom: 1.25rem;
   647→  font-size: 0.85rem;
   648→}
   649→.toc-toggle {
   650→  background: none;
   651→  border: none;
   652→  color: var(--text-muted);
   653→  font-size: 0.8rem;
   654→  font-weight: 600;
   655→  text-transform: uppercase;
   656→  letter-spacing: 0.05em;
   657→  cursor: pointer;
   658→  padding: 0;
   659→  display: flex;
   660→  align-items: center;
   661→  gap: 0.35rem;
   662→}
   663→.toc-toggle:hover { color: var(--text); }
   664→.toc-list {
   665→  list-style: none;
   666→  padding: 0;
   667→  margin: 0.5rem 0 0;
   668→}
   669→.toc-list li { margin-bottom: 0.2rem; }
   670→.toc-list a { color: var(--accent); }
   671→.toc-list a:hover { text-decoration: underline; }
   672→.toc-list[hidden] { display: none; }
   673→.toc-arrow { transition: transform 0.15s; }
   674→.toc-toggle[aria-expanded="false"] .toc-arrow { transform: rotate(-90deg); }
   675→
   676→/* ── Callouts ── */
   677→.callout {
   678→  border-left: 4px solid;
   679→  border-radius: 6px;
   680→  padding: 0.85rem 1rem;
   681→  margin: 0.75rem 0;
   682→  font-size: 0.9rem;
   683→}
   684→.callout-title {
   685→  font-weight: 600;
   686→  margin-bottom: 0.4rem;
   687→  font-size: 0.88rem;
   688→  text-transform: capitalize;
   689→}
   690→.callout-body p { margin-bottom: 0.35rem; }
   691→.callout-body p:last-child { margin-bottom: 0; }
   692→.callout-note     { background: #1f6feb22; border-color: #58a6ff; }
   693→.callout-tip      { background: #1a7f3722; border-color: #3fb950; }
   694→.callout-info     { background: #1f6feb22; border-color: #58a6ff; }
   695→.callout-success  { background: #1a7f3722; border-color: #3fb950; }
   696→.callout-important { background: #6e40c922; border-color: #bc8cff; }
   697→.callout-warning  { background: #d2992222; border-color: #d29922; }
   698→.callout-caution  { background: #f8514922; border-color: #f85149; }
   699→.callout-error    { background: #f8514922; border-color: #f85149; }
   700→[data-theme="light"] .callout-note,
   701→[data-theme="light"] .callout-info    { background: #ddf4ff; border-color: #0969da; }
   702→[data-theme="light"] .callout-tip,
   703→[data-theme="light"] .callout-success { background: #dafbe1; border-color: #1a7f37; }
   704→[data-theme="light"] .callout-important { background: #fbefff; border-color: #8250df; }
   705→[data-theme="light"] .callout-warning { background: #fff8c5; border-color: #9a6700; }
   706→[data-theme="light"] .callout-caution,
   707→[data-theme="light"] .callout-error   { background: #ffebe9; border-color: #cf222e; }
   708→
   709→/* ── Mermaid diagrams ── */
   710→pre.mermaid {
   711→  background: var(--bg-secondary);
   712→  border: 1px solid var(--border);
   713→  border-radius: 8px;
   714→  padding: 1rem;
   715→  text-align: center;
   716→  overflow-x: auto;
   717→}
   718→
   719→/* ── Reader Mode ── */
   720→.reader-mode .sidebar,
   721→.reader-mode .topbar,
   722→.reader-mode .breadcrumb,
   723→.reader-mode .meta-table,
   724→.reader-mode .backlinks { display: none !important; }
   725→.reader-mode .main-content { margin-left: 0 !important; }
   726→.reader-mode .container { max-width: 720px; }
   727→.reader-toggle-btn {
   728→  background: none;
   729→  border: 1px solid var(--border);
   730→  color: var(--text-muted);
   731→  border-radius: 6px;
   732→  padding: 0.3rem 0.6rem;
   733→  cursor: pointer;
   734→  font-size: 0.8rem;
   735→}
   736→.reader-toggle-btn:hover { color: var(--text); background: var(--bg-card); }
   737→
   738→/* ── Tag badges ── */
   739→.tag-list { display: flex; flex-wrap: wrap; gap: 0.3rem; margin-top: 0.35rem; }
   740→.tag {
   741→  display: inline-block;
   742→  background: var(--bg-secondary);
   743→  border: 1px solid var(--border);
   744→  color: var(--text-muted);
   745→  border-radius: 999px;
   746→  padding: 0.15rem 0.55rem;
   747→  font-size: 0.72rem;
   748→  cursor: pointer;
   749→  transition: background 0.15s, color 0.15s;
   750→}
   751→.tag:hover { background: var(--accent); color: #fff; border-color: var(--accent); }
   752→
   753→/* ── Search filter dropdowns ── */
   754→.search-filter-select {
   755→  background: var(--bg-card);
   756→  border: 1px solid var(--border);
   757→  color: var(--text);
   758→  border-radius: 6px;
   759→  padding: 0.35rem 0.6rem;
   760→  font-size: 0.875rem;
   761→  cursor: pointer;
   762→}
   763→.search-filter-select:focus {
   764→  outline: 2px solid var(--accent);
   765→  outline-offset: 1px;
   766→}
   767→
   768→/* ── View Transitions ── */
   769→@media (prefers-reduced-motion: no-preference) {
   770→  ::view-transition-old(root) {
   771→    animation: 90ms cubic-bezier(0.4, 0, 1, 1) both vt-fade-out;
   772→  }
   773→  ::view-transition-new(root) {
   774→    animation: 210ms cubic-bezier(0, 0, 0.2, 1) both vt-fade-in;
   775→  }
   776→}
   777→@keyframes vt-fade-out { to { opacity: 0; } }
   778→@keyframes vt-fade-in { from { opacity: 0; } }
   779→`
   780→

