     1→/**
     2→ * GitHub Dark-inspired CSS for the report website.
     3→ * Self-contained — no external CDN dependencies.
     4→ * Supports dark (default) and light themes, sidebar navigation, responsive layout.
     5→ */
     6→
     7→export const REPORT_CSS = `
     8→:root {
     9→  --bg: #0d1117;
    10→  --bg-secondary: #161b22;
    11→  --bg-card: #21262d;
    12→  --border: #30363d;
    13→  --text: #e6edf3;
    14→  --text-muted: #8b949e;
    15→  --accent: #58a6ff;
    16→  --accent-hover: #79b8ff;
    17→  --green-0: #161b22;
    18→  --green-1: #0e4429;
    19→  --green-2: #006d32;
    20→  --green-3: #26a641;
    21→  --green-4: #39d353;
    22→  --user-bg: #1c2d3e;
    23→  --user-border: #388bfd44;
    24→  --assistant-bg: #1c1c1c;
    25→  --assistant-border: #30363d;
    26→  --code-bg: #161b22;
    27→  --badge-codex: #1f6feb;
    28→  --badge-claude: #6e40c9;
    29→  --badge-gemini: #1a7f37;
    30→  --danger: #f85149;
    31→  --warning: #d29922;
    32→  --success: #3fb950;
    33→  --mark-bg: #3d3000;
    34→  --sidebar-width: 240px;
    35→  --font-mono: 'SF Mono', 'Consolas', 'Liberation Mono', 'Menlo', monospace;
    36→}
    37→
    38→[data-theme="light"] {
    39→  --bg: #ffffff;
    40→  --bg-secondary: #f6f8fa;
    41→  --bg-card: #ffffff;
    42→  --border: #d0d7de;
    43→  --text: #1f2328;
    44→  --text-muted: #636c76;
    45→  --accent: #0969da;
    46→  --accent-hover: #0550ae;
    47→  --user-bg: #ddf4ff;
    48→  --user-border: #54aeff44;
    49→  --assistant-bg: #f6f8fa;
    50→  --assistant-border: #d0d7de;
    51→  --code-bg: #f6f8fa;
    52→  --mark-bg: #fff8c5;
    53→  --green-0: #f6f8fa;
    54→  --green-1: #acf2bd;
    55→  --green-2: #40c463;
    56→  --green-3: #30a14e;
    57→  --green-4: #216e39;
    58→}
    59→
    60→*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    61→
    62→html { font-size: 16px; scroll-behavior: smooth; }
    63→
    64→body {
    65→  background: var(--bg);
    66→  color: var(--text);
    67→  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
    68→  line-height: 1.6;
    69→  min-height: 100vh;
    70→  display: flex;
    71→  flex-direction: column;
    72→}
    73→
    74→a { color: var(--accent); text-decoration: none; }
    75→a:hover { color: var(--accent-hover); text-decoration: underline; }
    76→
    77→code {
    78→  font-family: var(--font-mono);
    79→  font-size: 0.875em;
    80→  background: var(--code-bg);
    81→  padding: 0.15em 0.4em;
    82→  border-radius: 4px;
    83→  border: 1px solid var(--border);
    84→}
    85→
    86→pre {
    87→  background: var(--code-bg);
    88→  border: 1px solid var(--border);
    89→  border-radius: 8px;
    90→  padding: 1rem;
    91→  overflow-x: auto;
    92→  margin: 0.75rem 0;
    93→}
    94→
    95→pre code {
    96→  background: none;
    97→  border: none;
    98→  padding: 0;
    99→  font-size: 0.875rem;
   100→}
   101→
   102→h1, h2, h3, h4, h5, h6 {
   103→  color: var(--text);
   104→  line-height: 1.3;
   105→  margin-bottom: 0.5rem;
   106→}
   107→
   108→h1 { font-size: 1.75rem; }
   109→h2 { font-size: 1.375rem; border-bottom: 1px solid var(--border); padding-bottom: 0.4rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }
   110→h3 { font-size: 1.125rem; }
   111→
   112→p { margin-bottom: 0.75rem; }
   113→
   114→ul, ol { padding-left: 1.5rem; margin-bottom: 0.75rem; }
   115→li { margin-bottom: 0.25rem; }
   116→
   117→table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
   118→th, td { padding: 0.5rem 0.75rem; text-align: left; border-bottom: 1px solid var(--border); }
   119→th { color: var(--text-muted); font-weight: 600; font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.05em; background: var(--bg-secondary); }
   120→tr:hover td { background: var(--bg-secondary); }
   121→
   122→/* ── Mobile topbar ── */
   123→.topbar {
   124→  display: none;
   125→  background: var(--bg-secondary);
   126→  border-bottom: 1px solid var(--border);
   127→  padding: 0 1rem;
   128→  align-items: center;
   129→  gap: 0.75rem;
   130→  height: 48px;
   131→  position: sticky;
   132→  top: 0;
   133→  z-index: 200;
   134→}
   135→
   136→.topbar-brand {
   137→  font-weight: 700;
   138→  font-size: 0.95rem;
   139→  color: var(--text);
   140→  flex: 1;
   141→}
   142→
   143→.topbar-actions {
   144→  display: flex;
   145→  align-items: center;
   146→  gap: 0.5rem;
   147→}
   148→
   149→.hamburger, .theme-toggle-btn {
   150→  background: none;
   151→  border: 1px solid var(--border);
   152→  color: var(--text);
   153→  border-radius: 6px;
   154→  padding: 0.3rem 0.5rem;
   155→  cursor: pointer;
   156→  font-size: 1rem;
   157→  line-height: 1;
   158→  display: flex;
   159→  align-items: center;
   160→  justify-content: center;
   161→}
   162→
   163→.hamburger:hover, .theme-toggle-btn:hover {
   164→  background: var(--bg-card);
   165→}
   166→
   167→/* ── Sidebar ── */
   168→.sidebar {
   169→  width: var(--sidebar-width);
   170→  background: var(--bg-secondary);
   171→  border-right: 1px solid var(--border);
   172→  position: fixed;
   173→  top: 0;
   174→  left: 0;
   175→  bottom: 0;
   176→  overflow-y: auto;
   177→  z-index: 150;
   178→  display: flex;
   179→  flex-direction: column;
   180→  transition: transform 0.2s ease;
   181→}
   182→
   183→.sidebar-header {
   184→  padding: 1rem 1.25rem;
   185→  border-bottom: 1px solid var(--border);
   186→  display: flex;
   187→  align-items: center;
   188→  justify-content: space-between;
   189→  flex-shrink: 0;
   190→}
   191→
   192→.sidebar-brand {
   193→  font-weight: 700;
   194→  font-size: 1rem;
   195→  color: var(--text);
   196→}
   197→
   198→.sidebar-nav {
   199→  flex: 1;
   200→  padding: 0.5rem 0;
   201→  overflow-y: auto;
   202→}
   203→
   204→.nav-section-label {
   205→  padding: 0.75rem 1.25rem 0.25rem;
   206→  font-size: 0.7rem;
   207→  font-weight: 600;
   208→  text-transform: uppercase;
   209→  letter-spacing: 0.08em;
   210→  color: var(--text-muted);
   211→}
   212→
   213→.nav-link {
   214→  display: flex;
   215→  align-items: center;
   216→  gap: 0.5rem;
   217→  padding: 0.45rem 1.25rem;
   218→  color: var(--text-muted);
   219→  font-size: 0.9rem;
   220→  transition: color 0.15s, background 0.15s;
   221→  border-radius: 0;
   222→}
   223→
   224→.nav-link:hover {
   225→  color: var(--text);
   226→  background: var(--bg-card);
   227→  text-decoration: none;
   228→}
   229→
   230→.nav-link.active {
   231→  color: var(--accent);
   232→  background: var(--bg-card);
   233→  border-left: 3px solid var(--accent);
   234→  padding-left: calc(1.25rem - 3px);
   235→}
   236→
   237→.sidebar-footer {
   238→  padding: 0.75rem 1.25rem;
   239→  border-top: 1px solid var(--border);
   240→  display: flex;
   241→  align-items: center;
   242→  gap: 0.5rem;
   243→  flex-shrink: 0;
   244→}
   245→
   246→.sidebar-footer .theme-toggle-btn {
   247→  font-size: 0.85rem;
   248→  padding: 0.25rem 0.6rem;
   249→  gap: 0.3rem;
   250→}
   251→
   252→/* ── Overlay (mobile) ── */
   253→.sidebar-overlay {
   254→  display: none;
   255→  position: fixed;
   256→  inset: 0;
   257→  background: rgba(0,0,0,0.5);
   258→  z-index: 140;
   259→}
   260→
   261→/* ── Main content ── */
   262→.main-content {
   263→  margin-left: var(--sidebar-width);
   264→  flex: 1;
   265→  min-height: 100vh;
   266→}
   267→
   268→.container {
   269→  max-width: 960px;
   270→  margin: 0 auto;
   271→  padding: 1.5rem;
   272→}
   273→
   274→.page-header { margin-bottom: 2rem; }
   275→.page-header h1 { font-size: 1.5rem; }
   276→.page-header .subtitle { color: var(--text-muted); font-size: 0.9rem; margin-top: 0.25rem; }
   277→
   278→/* ── Cards ── */
   279→.card {
   280→  background: var(--bg-card);
   281→  border: 1px solid var(--border);
   282→  border-radius: 8px;
   283→  padding: 1.25rem;
   284→  margin-bottom: 1rem;
   285→}
   286→
   287→.card-title {
   288→  font-size: 0.8rem;
   289→  font-weight: 600;
   290→  text-transform: uppercase;
   291→  letter-spacing: 0.05em;
   292→  color: var(--text-muted);
   293→  margin-bottom: 0.5rem;
   294→}
   295→
   296→.stat-value {
   297→  font-size: 2rem;
   298→  font-weight: 700;
   299→  color: var(--text);
   300→  line-height: 1;
   301→}
   302→
   303→.stat-label { font-size: 0.85rem; color: var(--text-muted); margin-top: 0.25rem; }
   304→
   305→.stats-grid {
   306→  display: grid;
   307→  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
   308→  gap: 1rem;
   309→  margin-bottom: 1.5rem;
   310→}
   311→
   312→/* ── Charts ── */
   313→.chart-grid {
   314→  display: grid;
   315→  grid-template-columns: 1fr 1fr;
   316→  gap: 1rem;
   317→  margin-bottom: 1.5rem;
   318→}
   319→
   320→@media (max-width: 900px) {
   321→  .chart-grid { grid-template-columns: 1fr; }
   322→}
   323→
   324→.chart-card {
   325→  background: var(--bg-card);
   326→  border: 1px solid var(--border);
   327→  border-radius: 8px;
   328→  padding: 1.25rem;
   329→}
   330→
   331→.chart-title {
   332→  font-size: 0.85rem;
   333→  font-weight: 600;
   334→  color: var(--text-muted);
   335→  margin-bottom: 1rem;
   336→}
   337→
   338→.chart-card svg { display: block; width: 100%; overflow: visible; }
   339→.chart-card.full-width { grid-column: 1 / -1; }
   340→
   341→/* ── Badge ── */
   342→.badge {
   343→  display: inline-block;
   344→  padding: 0.2em 0.6em;
   345→  border-radius: 12px;
   346→  font-size: 0.75rem;
   347→  font-weight: 600;
   348→  text-transform: uppercase;
   349→  letter-spacing: 0.04em;
   350→}
   351→
   352→.badge-codex { background: #1f6feb33; color: #58a6ff; border: 1px solid #1f6feb66; }
   353→.badge-claude { background: #6e40c933; color: #bc8cff; border: 1px solid #6e40c966; }
   354→.badge-gemini { background: #1a7f3733; color: #3fb950; border: 1px solid #1a7f3766; }
   355→.badge-unknown { background: #30363d33; color: #8b949e; border: 1px solid #30363d66; }
   356→
   357→/* ── Tab bar ── */
   358→.tab-bar {
   359→  display: flex;
   360→  gap: 0.25rem;
   361→  margin-bottom: 1.25rem;
   362→  flex-wrap: wrap;
   363→}
   364→
   365→.tab-btn {
   366→  background: var(--bg-card);
   367→  border: 1px solid var(--border);
   368→  color: var(--text-muted);
   369→  padding: 0.35rem 0.9rem;
   370→  border-radius: 6px;
   371→  font-size: 0.85rem;
   372→  cursor: pointer;
   373→  transition: all 0.15s;
   374→}
   375→
   376→.tab-btn:hover { color: var(--text); border-color: var(--accent); }
   377→.tab-btn.active { color: var(--accent); border-color: var(--accent); background: var(--bg-secondary); }
   378→
   379→/* ── Messages ── */
   380→.messages { display: flex; flex-direction: column; gap: 0.75rem; margin-top: 1rem; }
   381→
   382→.message {
   383→  border-radius: 8px;
   384→  padding: 1rem;
   385→  border: 1px solid;
   386→  max-width: 100%;
   387→}
   388→
   389→.message-user {
   390→  background: var(--user-bg);
   391→  border-color: var(--user-border);
   392→  align-self: flex-start;
   393→}
   394→
   395→.message-assistant {
   396→  background: var(--assistant-bg);
   397→  border-color: var(--assistant-border);
   398→}
   399→
   400→.message-header {
   401→  display: flex;
   402→  align-items: center;
   403→  gap: 0.5rem;
   404→  margin-bottom: 0.5rem;
   405→  font-size: 0.8rem;
   406→  color: var(--text-muted);
   407→}
   408→
   409→.message-role {
   410→  font-weight: 600;
   411→  font-size: 0.8rem;
   412→  text-transform: capitalize;
   413→}
   414→
   415→.message-user .message-role { color: var(--accent); }
   416→.message-assistant .message-role { color: var(--text-muted); }
   417→
   418→.message-body { font-size: 0.9rem; line-height: 1.7; word-break: break-word; }
   419→.message-body p { margin-bottom: 0.5rem; }
   420→.message-body p:last-child { margin-bottom: 0; }
   421→
   422→/* ── Summary card ── */
   423→.summary-card {
   424→  background: var(--bg-secondary);
   425→  border: 1px solid var(--border);
   426→  border-left: 3px solid var(--accent);
   427→  border-radius: 6px;
   428→  padding: 1rem 1.25rem;
   429→  margin-bottom: 1.25rem;
   430→  font-size: 0.9rem;
   431→  color: var(--text-muted);
   432→}
   433→
   434→.summary-card .summary-label {
   435→  font-size: 0.75rem;
   436→  font-weight: 600;
   437→  text-transform: uppercase;
   438→  letter-spacing: 0.05em;
   439→  color: var(--accent);
   440→  margin-bottom: 0.4rem;
   441→}
   442→
   443→/* ── Metadata table ── */
   444→.meta-table { font-size: 0.85rem; margin-bottom: 1.25rem; }
   445→.meta-table td:first-child { color: var(--text-muted); width: 140px; font-weight: 500; }
   446→
   447→/* ── Backlinks ── */
   448→.backlinks {
   449→  background: var(--bg-secondary);
   450→  border: 1px solid var(--border);
   451→  border-radius: 6px;
   452→  padding: 0.75rem 1rem;
   453→  margin-bottom: 1.25rem;
   454→  font-size: 0.85rem;
   455→}
   456→
   457→.backlinks-title { font-weight: 600; color: var(--text-muted); margin-bottom: 0.4rem; font-size: 0.8rem; text-transform: uppercase; }
   458→.backlinks ul { padding-left: 1rem; }
   459→
   460→/* ── Search ── */
   461→.search-box {
   462→  width: 100%;
   463→  background: var(--bg-card);
   464→  border: 1px solid var(--border);
   465→  border-radius: 8px;
   466→  padding: 0.75rem 1rem;
   467→  color: var(--text);
   468→  font-size: 1rem;
   469→  font-family: inherit;
   470→  margin-bottom: 1rem;
   471→  outline: none;
   472→  transition: border-color 0.15s;
   473→}
   474→
   475→.search-box:focus { border-color: var(--accent); }
   476→
   477→.search-results { display: flex; flex-direction: column; gap: 0.75rem; }
   478→
   479→.search-result {
   480→  background: var(--bg-card);
   481→  border: 1px solid var(--border);
   482→  border-radius: 8px;
   483→  padding: 1rem;
   484→  transition: border-color 0.15s;
   485→}
   486→
   487→.search-result:hover { border-color: var(--accent); }
   488→.search-result-title { font-weight: 600; margin-bottom: 0.25rem; }
   489→.search-result-meta { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 0.5rem; }
   490→.search-result-snippet { font-size: 0.85rem; color: var(--text-muted); }
   491→.search-result mark { background: var(--mark-bg); color: var(--warning); border-radius: 2px; padding: 0 0.1em; }
   492→#search-count { font-size: 0.85rem; color: var(--text-muted); margin-bottom: 0.75rem; }
   493→
   494→/* ── Heatmap legend ── */
   495→.heatmap-legend {
   496→  display: flex;
   497→  align-items: center;
   498→  gap: 0.4rem;
   499→  font-size: 0.75rem;
   500→  color: var(--text-muted);
   501→  margin-top: 0.5rem;
   502→  justify-content: flex-end;
   503→}
   504→
   505→/* ── Popover ── */
   506→.popover {
   507→  position: fixed;
   508→  z-index: 500;
   509→  background: var(--bg-card);
   510→  border: 1px solid var(--border);
   511→  border-radius: 8px;
   512→  padding: 0.75rem 1rem;
   513→  max-width: 320px;
   514→  font-size: 0.85rem;
   515→  box-shadow: 0 8px 24px rgba(0,0,0,0.4);
   516→  pointer-events: none;
   517→}
   518→
   519→.popover-meta { color: var(--text-muted); font-size: 0.78rem; margin-bottom: 0.4rem; }
   520→.popover-summary { color: var(--text); line-height: 1.5; }
   521→
   522→/* ── Graph canvas ── */
   523→#graph-canvas {
   524→  display: block;
   525→  width: 100%;
   526→  height: 600px;
   527→  border: 1px solid var(--border);
   528→  border-radius: 8px;
   529→  background: var(--bg-secondary);
   530→  cursor: grab;
   531→}
   532→
   533→#graph-canvas:active { cursor: grabbing; }
   534→
   535→.graph-legend {
   536→  display: flex;
   537→  gap: 1.25rem;
   538→  flex-wrap: wrap;
   539→  margin-top: 0.75rem;
   540→  font-size: 0.8rem;
   541→  color: var(--text-muted);
   542→}
   543→
   544→.graph-legend-item {
   545→  display: flex;
   546→  align-items: center;
   547→  gap: 0.4rem;
   548→}
   549→
   550→.graph-legend-dot {
   551→  width: 10px;
   552→  height: 10px;
   553→  border-radius: 50%;
   554→  flex-shrink: 0;
   555→}
   556→
   557→/* ── Project cards ── */
   558→.project-grid {
   559→  display: grid;
   560→  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
   561→  gap: 1rem;
   562→  margin-bottom: 1.5rem;
   563→}
   564→
   565→.project-card {
   566→  background: var(--bg-card);
   567→  border: 1px solid var(--border);
   568→  border-radius: 8px;
   569→  padding: 1.25rem;
   570→  transition: border-color 0.15s;
   571→}
   572→
   573→.project-card:hover { border-color: var(--accent); }
   574→.project-card-name { font-weight: 700; font-size: 1.05rem; margin-bottom: 0.5rem; }
   575→.project-card-meta { font-size: 0.82rem; color: var(--text-muted); }
   576→.project-card-clients { margin-top: 0.6rem; display: flex; gap: 0.35rem; flex-wrap: wrap; }
   577→
   578→/* ── Responsive: tablet icon mode (768–1024px) ── */
   579→@media (max-width: 1024px) and (min-width: 769px) {
   580→  :root { --sidebar-width: 52px; }
   581→  .nav-link .nav-label { display: none; }
   582→  .nav-link { justify-content: center; padding: 0.55rem; gap: 0; }
   583→  .nav-section-label { display: none; }
   584→  .sidebar-brand { display: none; }
   585→  .sidebar-footer .theme-label { display: none; }
   586→  .sidebar-footer .theme-toggle-btn { padding: 0.35rem 0.5rem; }
   587→}
   588→
   589→/* ── Responsive: mobile (<768px) ── */
   590→@media (max-width: 768px) {
   591→  .topbar { display: flex; }
   592→  .sidebar {
   593→    transform: translateX(-100%);
   594→    top: 48px;
   595→  }
   596→  .sidebar.open { transform: translateX(0); }
   597→  .sidebar-overlay.open { display: block; }
   598→  .main-content { margin-left: 0; }
   599→  .container { padding: 1rem 0.75rem; }
   600→  .stats-grid { grid-template-columns: repeat(2, 1fr); }
   601→  .project-grid { grid-template-columns: 1fr; }
   602→}
   603→
   604→/* ── Sidebar collapse ── */
   605→body.sidebar-collapsed .sidebar { width: 52px; }
   606→body.sidebar-collapsed .nav-label { display: none; }
   607→body.sidebar-collapsed .nav-link { justify-content: center; padding: 0.55rem; gap: 0; }
   608→body.sidebar-collapsed .nav-section-label { display: none; }
   609→body.sidebar-collapsed .sidebar-brand { display: none; }
   610→body.sidebar-collapsed .theme-label { display: none; }
   611→body.sidebar-collapsed .main-content { margin-left: 52px; }
   612→.sidebar-collapse-btn {
   613→  background: none;
   614→  border: 1px solid var(--border);
   615→  color: var(--text-muted);
   616→  border-radius: 6px;
   617→  padding: 0.25rem 0.5rem;
   618→  cursor: pointer;
   619→  font-size: 0.75rem;
   620→  line-height: 1;
   621→}
   622→.sidebar-collapse-btn:hover { color: var(--text); background: var(--bg-card); }
   623→
   624→/* ── Breadcrumb ── */
   625→.breadcrumb {
   626→  display: flex;
   627→  align-items: center;
   628→  flex-wrap: wrap;
   629→  gap: 0.25rem;
   630→  font-size: 0.82rem;
   631→  color: var(--text-muted);
   632→  margin-bottom: 1rem;
   633→}
   634→.breadcrumb-item { color: var(--text-muted); }
   635→a.breadcrumb-item { color: var(--accent); text-decoration: none; }
   636→a.breadcrumb-item:hover { text-decoration: underline; }
   637→.breadcrumb-sep { color: var(--border); user-select: none; }
   638→
   639→/* ── TOC ── */
   640→.toc {
   641→  background: var(--bg-secondary);
   642→  border: 1px solid var(--border);
   643→  border-left: 3px solid var(--accent);
   644→  border-radius: 6px;
   645→  padding: 0.75rem 1rem;
   646→  margin-bottom: 1.25rem;
   647→  font-size: 0.85rem;
   648→}
   649→.toc-toggle {
   650→  background: none;
   651→  border: none;
   652→  color: var(--text-muted);
   653→  font-size: 0.8rem;
   654→  font-weight: 600;
   655→  text-transform: uppercase;
   656→  letter-spacing: 0.05em;
   657→  cursor: pointer;
   658→  padding: 0;
   659→  display: flex;
   660→  align-items: center;
   661→  gap: 0.35rem;
   662→}
   663→.toc-toggle:hover { color: var(--text); }
   664→.toc-list {
   665→  list-style: none;
   666→  padding: 0;
   667→  margin: 0.5rem 0 0;
   668→}
   669→.toc-list li { margin-bottom: 0.2rem; }
   670→.toc-list a { color: var(--accent); }
   671→.toc-list a:hover { text-decoration: underline; }
   672→.toc-list[hidden] { display: none; }
   673→.toc-arrow { transition: transform 0.15s; }
   674→.toc-toggle[aria-expanded="false"] .toc-arrow { transform: rotate(-90deg); }
   675→
   676→/* ── Callouts ── */
   677→.callout {
   678→  border-left: 4px solid;
   679→  border-radius: 6px;
   680→  padding: 0.85rem 1rem;
   681→  margin: 0.75rem 0;
   682→  font-size: 0.9rem;
   683→}
   684→.callout-title {
   685→  font-weight: 600;
   686→  margin-bottom: 0.4rem;
   687→  font-size: 0.88rem;
   688→  text-transform: capitalize;
   689→}
   690→.callout-body p { margin-bottom: 0.35rem; }
   691→.callout-body p:last-child { margin-bottom: 0; }
   692→.callout-note     { background: #1f6feb22; border-color: #58a6ff; }
   693→.callout-tip      { background: #1a7f3722; border-color: #3fb950; }
   694→.callout-info     { background: #1f6feb22; border-color: #58a6ff; }
   695→.callout-success  { background: #1a7f3722; border-color: #3fb950; }
   696→.callout-important { background: #6e40c922; border-color: #bc8cff; }
   697→.callout-warning  { background: #d2992222; border-color: #d29922; }
   698→.callout-caution  { background: #f8514922; border-color: #f85149; }
   699→.callout-error    { background: #f8514922; border-color: #f85149; }
   700→[data-theme="light"] .callout-note,
   701→[data-theme="light"] .callout-info    { background: #ddf4ff; border-color: #0969da; }
   702→[data-theme="light"] .callout-tip,
   703→[data-theme="light"] .callout-success { background: #dafbe1; border-color: #1a7f37; }
   704→[data-theme="light"] .callout-important { background: #fbefff; border-color: #8250df; }
   705→[data-theme="light"] .callout-warning { background: #fff8c5; border-color: #9a6700; }
   706→[data-theme="light"] .callout-caution,
   707→[data-theme="light"] .callout-error   { background: #ffebe9; border-color: #cf222e; }
   708→
   709→/* ── Mermaid diagrams ── */
   710→pre.mermaid {
   711→  background: var(--bg-secondary);
   712→  border: 1px solid var(--border);
   713→  border-radius: 8px;
   714→  padding: 1rem;
   715→  text-align: center;
   716→  overflow-x: auto;
   717→}
   718→
   719→/* ── Reader Mode ── */
   720→.reader-mode .sidebar,
   721→.reader-mode .topbar,
   722→.reader-mode .breadcrumb,
   723→.reader-mode .meta-table,
   724→.reader-mode .backlinks { display: none !important; }
   725→.reader-mode .main-content { margin-left: 0 !important; }
   726→.reader-mode .container { max-width: 720px; }
   727→.reader-toggle-btn {
   728→  background: none;
   729→  border: 1px solid var(--border);
   730→  color: var(--text-muted);
   731→  border-radius: 6px;
   732→  padding: 0.3rem 0.6rem;
   733→  cursor: pointer;
   734→  font-size: 0.8rem;
   735→}
   736→.reader-toggle-btn:hover { color: var(--text); background: var(--bg-card); }
   737→
   738→/* ── Tag badges ── */
   739→.tag-list { display: flex; flex-wrap: wrap; gap: 0.3rem; margin-top: 0.35rem; }
   740→.tag {
   741→  display: inline-block;
   742→  background: var(--bg-secondary);
   743→  border: 1px solid var(--border);
   744→  color: var(--text-muted);
   745→  border-radius: 999px;
   746→  padding: 0.15rem 0.55rem;
   747→  font-size: 0.72rem;
   748→  cursor: pointer;
   749→  transition: background 0.15s, color 0.15s;
   750→}
   751→.tag:hover { background: var(--accent); color: #fff; border-color: var(--accent); }
   752→
   753→/* ── Search filter dropdowns ── */
   754→.search-filter-select {
   755→  background: var(--bg-card);
   756→  border: 1px solid var(--border);
   757→  color: var(--text);
   758→  border-radius: 6px;
   759→  padding: 0.35rem 0.6rem;
   760→  font-size: 0.875rem;
   761→  cursor: pointer;
   762→}
   763→.search-filter-select:focus {
   764→  outline: 2px solid var(--accent);
   765→  outline-offset: 1px;
   766→}
   767→
   768→/* ── View Transitions ── */
   769→@media (prefers-reduced-motion: no-preference) {
   770→  ::view-transition-old(root) {
