     1→/**
     2→ * Knowledge graph page: force-directed visualization of sessions and knowledge links.
     3→ * Inline vanilla JS, no CDN dependencies.
     4→ */
     5→
     6→import type { ManifestEntry } from '@openmnemo/types'
     7→import type { LinkGraph } from '../types.js'
     8→import type { Translations } from '../i18n/types.js'
     9→import type { MarkdownFile } from './layout.js'
    10→import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot, slugifyName } from './layout.js'
    11→
    12→const MAX_NODES = 500
    13→
    14→// ---------------------------------------------------------------------------
    15→// Graph data types
    16→// ---------------------------------------------------------------------------
    17→
    18→interface GraphNode {
    19→  id: string
    20→  label: string
    21→  type: 'session' | 'knowledge'
    22→  client?: string
    23→  url: string
    24→}
    25→
    26→interface GraphEdge {
    27→  source: string
    28→  target: string
    29→}
    30→
    31→// ---------------------------------------------------------------------------
    32→// Build graph data
    33→// ---------------------------------------------------------------------------
    34→
    35→export function buildGraphData(
    36→  manifests: ManifestEntry[],
    37→  knowledgeFiles: MarkdownFile[],
    38→  linkGraph: LinkGraph,
    39→): { nodes: GraphNode[]; edges: GraphEdge[] } {
    40→  // Cap manifests to MAX_NODES (most recent first)
    41→  const sorted = [...manifests]
    42→    .sort((a, b) => b.started_at.localeCompare(a.started_at))
    43→    .slice(0, MAX_NODES)
    44→
    45→  const nodeSet = new Set<string>()
    46→  const nodes: GraphNode[] = []
    47→  const edges: GraphEdge[] = []
    48→
    49→  for (const m of sorted) {
    50→    if (!nodeSet.has(m.session_id)) {
    51→      nodeSet.add(m.session_id)
    52→      nodes.push({
    53→        id: m.session_id,
    54→        label: m.title || m.session_id.slice(0, 8),
    55→        type: 'session',
    56→        client: m.client,
    57→        url: transcriptUrlFromRoot(m),
    58→      })
    59→    }
    60→  }
    61→
    62→  for (const kf of knowledgeFiles) {
    63→    const id = `knowledge:${kf.filename}`
    64→    if (!nodeSet.has(id)) {
    65→      nodeSet.add(id)
    66→      nodes.push({
    67→        id,
    68→        label: kf.title || kf.filename,
    69→        type: 'knowledge',
    70→        url: `knowledge/index.html#${slugifyName(kf.filename)}`,
    71→      })
    72→    }
    73→  }
    74→
    75→  // Add edges from link graph (only for nodes that exist)
    76→  for (const [sourceId, targets] of Object.entries(linkGraph.forwardLinks)) {
    77→    if (!nodeSet.has(sourceId)) continue
    78→    for (const targetId of targets) {
    79→      if (nodeSet.has(targetId)) {
    80→        edges.push({ source: sourceId, target: targetId })
    81→      }
    82→    }
    83→  }
    84→
    85→  return { nodes, edges }
    86→}
    87→
    88→// ---------------------------------------------------------------------------
    89→// Graph page renderer
    90→
    91→export function renderGraph(
    92→  manifests: ManifestEntry[],
    93→  knowledgeFiles: MarkdownFile[],
    94→  linkGraph: LinkGraph,
    95→  t?: Translations,
    96→): string {
    97→  const nav = renderNav('graph', 0, t)
    98→  const title = t?.graph.title ?? 'Knowledge Graph'
    99→  const subtitle = t?.graph.subtitle ?? 'Connections between sessions and knowledge files'
   100→
   101→  const { nodes, edges } = buildGraphData(manifests, knowledgeFiles, linkGraph)
   102→
   103→  if (nodes.length === 0) {
   104→    const content = `<div class="page-header">
   105→  <h1>${escHtml(title)}</h1>
   106→  <p class="subtitle">${escHtml(t?.graph.noData ?? 'No graph data available.')}</p>
   107→</div>`
   108→    return htmlShell(title, content, nav)
   109→  }
   110→
   111→  // Embed graph data as JSON; escape sequences that could break a <script> block
   112→  const graphDataJson = JSON.stringify({ nodes, edges })
   113→    .replace(/<\//g, '<\\/')
   114→    .replace(/\u2028/g, '\\u2028')
   115→    .replace(/\u2029/g, '\\u2029')
   116→
   117→  const graphScript = `<script>
   118→(function() {
   119→var GRAPH_DATA = ${graphDataJson};
   120→
   121→// Client color map
   122→var CLIENT_COLORS = { claude: '#bc8cff', codex: '#58a6ff', gemini: '#3fb950' };
   123→function nodeColor(n) {
   124→  if (n.type === 'knowledge') return '#f0c040';
   125→  return CLIENT_COLORS[n.client] || '#8b949e';
   126→}
   127→function nodeRadius(n) { return n.type === 'knowledge' ? 7 : 5; }
   128→
   129→var canvas = document.getElementById('graph-canvas');
   130→if (!canvas) return;
   131→var ctx = canvas.getContext('2d');
   132→
   133→// High-DPI
   134→function resize() {
   135→  var rect = canvas.getBoundingClientRect();
   136→  var dpr = window.devicePixelRatio || 1;
   137→  canvas.width = rect.width * dpr;
   138→  canvas.height = rect.height * dpr;
   139→  ctx.scale(dpr, dpr);
   140→}
   141→resize();
   142→window.addEventListener('resize', function() { resize(); draw(); });
   143→
   144→var W = canvas.getBoundingClientRect().width;
   145→var H = canvas.getBoundingClientRect().height;
   146→
   147→// Init positions (random spread)
   148→var nodeMap = {};
   149→var simNodes = GRAPH_DATA.nodes.map(function(n) {
   150→  var sn = { id: n.id, label: n.label, type: n.type, client: n.client, url: n.url,
   151→    x: W/2 + (Math.random()-0.5)*W*0.7, y: H/2 + (Math.random()-0.5)*H*0.7, vx: 0, vy: 0 };
   152→  nodeMap[n.id] = sn;
   153→  return sn;
   154→});
   155→
   156→var simEdges = GRAPH_DATA.edges.map(function(e) {
   157→  return { source: nodeMap[e.source], target: nodeMap[e.target] };
   158→}).filter(function(e) { return e.source && e.target; });
   159→
   160→// Simulation params — tuned for ~50–200 node graphs on a 900px canvas
   161→var ALPHA = 1.0;        // initial energy; decays each tick
   162→var ALPHA_DECAY = 0.0228; // decay rate ≈ ln(0.001)/300 (settles in ~300 ticks)
   163→var ALPHA_MIN = 0.001;  // stop simulation below this threshold
   164→var CHARGE = -120;      // repulsion strength between nodes (negative = push apart)
   165→var LINK_DIST = 80;     // spring rest length in pixels
   166→var CENTER_FORCE = 0.05; // gravity toward canvas center (prevents drift)
   167→var DAMPING = 0.6;      // velocity damping per tick (higher = faster settling)
   168→
